import{_ as a,o as s,c as n,aQ as i}from"./chunks/framework.cDvftfeu.js";const u=JSON.parse('{"title":"Ham Web","description":"Ham Web frontend architecture and features.","frontmatter":{"description":"Ham Web frontend architecture and features.","prev":{"text":"Brand Assets","link":"/en/developers/open-platform/brand-assets"},"next":{"text":"SSO OAuth2 Authorization","link":"/en/developers/ham-web/sso-authorize"}},"headers":[],"relativePath":"en/developers/ham-web/index.md","filePath":"en/developers/ham-web/index.md","lastUpdated":1777525243000}'),t={name:"en/developers/ham-web/index.md"};function l(o,e,r,p,h,d){return s(),n("div",null,[...e[0]||(e[0]=[i(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /developers/ham-web.md for this page in Markdown format</div><h1 id="ham-web" tabindex="-1">Ham Web <a class="header-anchor" href="#ham-web" aria-label="Permalink to &quot;Ham Web&quot;">​</a></h1><p><a href="https://github.com/whu-ham/ham-web" target="_blank" rel="noreferrer">Ham Web</a> is the web frontend for Ham, primarily serving the SSO single sign-on authorization flow and acting as the web entry point for the Ham Connect platform.</p><h2 id="where-it-is-used" tabindex="-1">Where It Is Used <a class="header-anchor" href="#where-it-is-used" aria-label="Permalink to &quot;Where It Is Used&quot;">​</a></h2><p>Once deployed, Ham Web serves as the web service endpoint for the Ham Connect platform. It is used in the following scenarios:</p><ul><li><strong>SSO Authorization Page</strong> — When third-party apps initiate OAuth2 authorization through the Ham Connect platform, users are redirected to Ham Web&#39;s authorization page for login and consent confirmation</li><li><strong>QR Code Login</strong> — Users can log in on the web by scanning a QR code with the Ham app</li><li><strong>Passkey Login</strong> — Supports WebAuthn / Passkey passwordless login</li><li><strong>Mobile H5 Fallback</strong> — When users don&#39;t have the Ham native app installed, provides a web-based install prompt and Passkey login option</li></ul><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h2><ul><li><strong>Framework</strong>: Next.js 16 (App Router) + React 19 + TypeScript</li><li><strong>Styling</strong>: Tailwind CSS v4 + HeroUI v3</li><li><strong>State Management</strong>: Jotai + React Redux</li><li><strong>i18n</strong>: next-intl (Chinese / English / Japanese)</li><li><strong>Deployment</strong>: Cloudflare Pages (via OpenNext)</li><li><strong>Tooling</strong>: ESLint v9 + Prettier + pnpm</li></ul><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><ul><li>Node.js &gt;= 20</li><li>pnpm</li></ul><h3 id="installation-running" tabindex="-1">Installation &amp; Running <a class="header-anchor" href="#installation-running" aria-label="Permalink to &quot;Installation &amp; Running&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Install dependencies</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Start dev server (Turbopack)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Production build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Cloudflare Pages build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:cf</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Lint</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lint</span></span></code></pre></div><p>Dev server runs at <code>http://localhost:3000</code>.</p><h2 id="project-structure" tabindex="-1">Project Structure <a class="header-anchor" href="#project-structure" aria-label="Permalink to &quot;Project Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>app/                # Next.js App Router entry</span></span>
<span class="line"><span>  api/              # API routes</span></span>
<span class="line"><span>    auth/           # Auth APIs (login, logout, refresh, passkey, QR code)</span></span>
<span class="line"><span>    sso/            # SSO APIs (consent confirmation, consent info)</span></span>
<span class="line"><span>  sso-authorize/    # SSO authorization page (login view, QR login, passkey login)</span></span>
<span class="line"><span>components/         # Shared UI components</span></span>
<span class="line"><span>  LanguageSwitcher  # Language switcher</span></span>
<span class="line"><span>  ThemeSwitcher     # Theme switcher</span></span>
<span class="line"><span>  SearchBar         # Search bar</span></span>
<span class="line"><span>i18n/               # next-intl runtime config</span></span>
<span class="line"><span>messages/           # Locale message catalogs (en.json / zh.json / ja.json)</span></span>
<span class="line"><span>services/           # API / service layer</span></span>
<span class="line"><span>store/              # State management (locale, theme)</span></span>
<span class="line"><span>public/             # Static assets</span></span></code></pre></div><h2 id="development-guide" tabindex="-1">Development Guide <a class="header-anchor" href="#development-guide" aria-label="Permalink to &quot;Development Guide&quot;">​</a></h2><h3 id="adding-new-ui-strings" tabindex="-1">Adding New UI Strings <a class="header-anchor" href="#adding-new-ui-strings" aria-label="Permalink to &quot;Adding New UI Strings&quot;">​</a></h3><p>Use <code>next-intl</code> for internationalization. When adding new strings, update all three translation files:</p><ul><li><code>messages/zh.json</code></li><li><code>messages/en.json</code></li><li><code>messages/ja.json</code></li></ul><h3 id="api-routes" tabindex="-1">API Routes <a class="header-anchor" href="#api-routes" aria-label="Permalink to &quot;API Routes&quot;">​</a></h3><p>Ham Web&#39;s API routes act as a backend proxy, forwarding requests to the Ham backend service:</p><ul><li><code>/api/auth/*</code> — Authentication (login, logout, token refresh, passkey, QR code)</li><li><code>/api/sso/*</code> — SSO authorization (consent info query, consent confirmation)</li></ul><h3 id="theme-language" tabindex="-1">Theme &amp; Language <a class="header-anchor" href="#theme-language" aria-label="Permalink to &quot;Theme &amp; Language&quot;">​</a></h3><ul><li>Supports light / dark / system theme modes</li><li>Supports Chinese / English / Japanese, with user preference persisted via cookies</li></ul><h2 id="ci-cd" tabindex="-1">CI/CD <a class="header-anchor" href="#ci-cd" aria-label="Permalink to &quot;CI/CD&quot;">​</a></h2><p>The project uses GitHub Actions for continuous integration and deploys to Cloudflare Pages.</p><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>All contributors must follow these rules:</p><ol><li>Run <code>pnpm lint</code> and <code>pnpm build</code> before committing</li><li>Commit messages must follow <a href="https://www.conventionalcommits.org/" target="_blank" rel="noreferrer">Conventional Commits</a></li><li>Commit messages and code comments must be in English</li></ol><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h2><p>Ham Web is <a href="https://opensource.org/licenses/MIT" target="_blank" rel="noreferrer">MIT licensed</a>.</p>`,32)])])}const g=a(t,[["render",l]]);export{u as __pageData,g as default};
